#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10,mod=666623333;

long long l,r,num[N],euler[N];

int main(){
    scanf("%lld%lld",&l,&r);
    for(long long i=l;i<=r;i++)
        num[i-l]=euler[i-l]=i;
    for(int i=2;i<=min(r,(long long)1e6);i++){
        for(long long j=(l+i-1)/i*i;j<=r;j+=i)
            if(num[j-l]%i==0){
                euler[j-l]=euler[j-l]/i*(i-1);
                while(num[j-l]%i==0)
                    num[j-l]/=i;
            }
    }
    long long ans=0;
    for(long long i=l;i<=r;i++){
        if(num[i-l]>1)
            euler[i-l]=euler[i-l]/num[i-l]*(num[i-l]-1);
        ans=(ans+i-euler[i-l])%mod;
    }
    printf("%lld",(ans+mod)%mod);
    return 0;
}
